 * university 2022 Scheme - Data Structures Topic
 */

#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

/* ================== PRIMITIVE DATA STRUCTURES ================== */
/* Primitive types are predefined by C language */

void demonstratePrimitives() {
 printf("\n=== PRIMITIVE DATA TYPES ===\n");

 // Integer - whole numbers (typically 4 bytes)
 int age = 25;
 int temperature = -5;
 printf("Integer: age=%d, temperature=%d\n", age, temperature);

 // Float - decimal numbers (typically 4 bytes)
 float price = 99.99f;
 printf("Float: price=%.2f\n", price);

 // Double - higher precision (typically 8 bytes)
 double pi = 3.14159265;
 printf("Double: pi=%.8f\n", pi);

 // Character - single character (1 byte)
 char grade = 'A';
 char symbol = '@';
 printf("Character: grade=%c, symbol=%c\n", grade, symbol);

 // Boolean - true/false (1 byte)
 bool isPassed = true;
 bool isRaining = false;
 printf("Boolean: isPassed=%d, isRaining=%d\n", isPassed, isRaining);

 // Pointer - stores memory address
 int num = 42;
 int *ptr = &num;
 printf("Pointer: value=%d, address=%p\n", *ptr, (void*)ptr);
}


/* ================== NON-PRIMITIVE: LINEAR ================== */

/* ---------- Array ---------- */
void demonstrateArray() {
 printf("\n=== ARRAY (Fixed Size) ===\n");

 // Declare and initialize array
 int marks[5] = {85, 90, 78, 92, 88};
 int i;

 // Access by index - O(1)
 printf("First element: marks[0] = %d\n", marks[0]);
 printf("Last element: marks[4] = %d\n", marks[4]);

 // Traverse - O(n)
 printf("All elements: ");
 for (i = 0; i < 5; i++) {
 printf("%d ", marks[i]);
 }
 printf("\n");

 // Search - O(n)
 int search = 78;
 for (i = 0; i < 5; i++) {
 if (marks[i] == search) {
 printf("Found %d at index %d\n", search, i);
 break;
 }
 }
}

/* ---------- Linked List ---------- */
struct Node {
 int data;
 struct Node *next;
};

struct LinkedList {
 struct Node *head;
};

void initLinkedList(struct LinkedList *list) {
 list->head = NULL;
}

void appendNode(struct LinkedList *list, int data) {
 // O(n) - traverse to end
 struct Node *newNode = (struct Node*)malloc(sizeof(struct Node));
 newNode->data = data;
 newNode->next = NULL;

 if (list->head == NULL) {
 list->head = newNode;
 return;
 }

 struct Node *current = list->head;
 while (current->next != NULL) {
 current = current->next;
 }
 current->next = newNode;
}

void prependNode(struct LinkedList *list, int data) {
 // O(1) - add at beginning
 struct Node *newNode = (struct Node*)malloc(sizeof(struct Node));
 newNode->data = data;
 newNode->next = list->head;
 list->head = newNode;
}

void displayLinkedList(struct LinkedList *list) {
 // O(n) - traverse
 struct Node *current = list->head;
 printf("Linked List: ");
 while (current != NULL) {
 printf("%d ", current->data);
 current = current->next;
 }
 printf("\n");
}

void freeLinkedList(struct LinkedList *list) {
 struct Node *current = list->head;
 struct Node *next;
 while (current != NULL) {
 next = current->next;
 free(current);
 current = next;
 }
 list->head = NULL;
}

/* ---------- Stack (LIFO) ---------- */
struct Stack {
 int *items;
 int top;
 int capacity;
};

void initStack(struct Stack *s, int capacity) {
 s->capacity = capacity;
 s->top = -1;
 s->items = (int*)malloc(capacity * sizeof(int));
}

bool isStackEmpty(struct Stack *s) {
 return s->top == -1;
}

bool isStackFull(struct Stack *s) {
 return s->top == s->capacity - 1;
}

void push(struct Stack *s, int item) {
 // O(1)
 if (!isStackFull(s)) {
 s->items[++s->top] = item;
 }
}

int pop(struct Stack *s) {
 // O(1)
 if (!isStackEmpty(s)) {
 return s->items[s->top--];
 }
 return -1;
}

int peek(struct Stack *s) {
 // O(1)
 if (!isStackEmpty(s)) {
 return s->items[s->top];
 }
 return -1;
}

void demonstrateStack() {
 printf("\n=== STACK (LIFO) ===\n");
 struct Stack s;
 initStack(&s, 10);

 push(&s, 10);
 push(&s, 20);
 push(&s, 30);

 printf("Top after pushes: %d\n", peek(&s));
 printf("Pop: %d\n", pop(&s)); // 30
 printf("Pop: %d\n", pop(&s)); // 20
 printf("Top after pops: %d\n", peek(&s)); // 10

 free(s.items);
}

/* ---------- Queue (FIFO) ---------- */
struct Queue {
 int *items;
 int front;
 int rear;
 int capacity;
 int size;
};

void initQueue(struct Queue *q, int capacity) {
 q->capacity = capacity;
 q->front = 0;
 q->rear = -1;
 q->size = 0;
 q->items = (int*)malloc(capacity * sizeof(int));
}

bool isQueueEmpty(struct Queue *q) {
 return q->size == 0;
}

bool isQueueFull(struct Queue *q) {
 return q->size == q->capacity;
}

void enqueue(struct Queue *q, int item) {
 // O(1)
 if (!isQueueFull(q)) {
 q->rear = (q->rear + 1) % q->capacity;
 q->items[q->rear] = item;
 q->size++;
 }
}

int dequeue(struct Queue *q) {
 // O(1)
 if (!isQueueEmpty(q)) {
 int item = q->items[q->front];
 q->front = (q->front + 1) % q->capacity;
 q->size--;
 return item;
 }
 return -1;
}

int queueFront(struct Queue *q) {
 // O(1)
 if (!isQueueEmpty(q)) {
 return q->items[q->front];
 }
 return -1;
}

void demonstrateQueue() {
 printf("\n=== QUEUE (FIFO) ===\n");
 struct Queue q;
 initQueue(&q, 10);

 enqueue(&q, 10);
 enqueue(&q, 20);
 enqueue(&q, 30);

 printf("Front after enqueues: %d\n", queueFront(&q));
 printf("Dequeue: %d\n", dequeue(&q)); // 10
 printf("Dequeue: %d\n", dequeue(&q)); // 20
 printf("Front after dequeues: %d\n", queueFront(&q)); // 30

 free(q.items);
}


/* ================== NON-PRIMITIVE: NON-LINEAR ================== */

/* ---------- Binary Tree ---------- */
struct TreeNode {
 int data;
 struct TreeNode *left;
 struct TreeNode *right;
};

struct TreeNode* createTreeNode(int data) {
 struct TreeNode *node = (struct TreeNode*)malloc(sizeof(struct TreeNode));
 node->data = data;
 node->left = NULL;
 node->right = NULL;
 return node;
}

void inorderTraversal(struct TreeNode *node) {
 // O(n)
 if (node != NULL) {
 inorderTraversal(node->left);
 printf("%d ", node->data);
 inorderTraversal(node->right);
 }
}

void preorderTraversal(struct TreeNode *node) {
 // O(n)
 if (node != NULL) {
 printf("%d ", node->data);
 preorderTraversal(node->left);
 preorderTraversal(node->right);
 }
}

void postorderTraversal(struct TreeNode *node) {
 // O(n)
 if (node != NULL) {
 postorderTraversal(node->left);
 postorderTraversal(node->right);
 printf("%d ", node->data);
 }
}

void demonstrateBinaryTree() {
 printf("\n=== BINARY TREE ===\n");
 /*
 * 10
 * / \
 * 5 15
 * / \ \
 * 3 7 20
 */
 struct TreeNode *root = createTreeNode(10);
 root->left = createTreeNode(5);
 root->right = createTreeNode(15);
 root->left->left = createTreeNode(3);
 root->left->right = createTreeNode(7);
 root->right->right = createTreeNode(20);

 printf("Inorder: ");
 inorderTraversal(root); // 3 5 7 10 15 20
 printf("\n");

 printf("Preorder: ");
 preorderTraversal(root); // 10 5 3 7 15 20
 printf("\n");

 printf("Postorder: ");
 postorderTraversal(root); // 3 7 5 20 15 10
 printf("\n");

 // Free memory
 free(root->left->left);
 free(root->left->right);
 free(root->left);
 free(root->right->right);
 free(root->right);
 free(root);
}

/* ---------- Graph (Adjacency List) ---------- */
#define MAX_VERTICES 100

struct Graph {
 int vertices;
 int adj[MAX_VERTICES][MAX_VERTICES];
};

void initGraph(struct Graph *g, int vertices) {
 g->vertices = vertices;
 int i, j;
 for (i = 0; i < vertices; i++) {
 for (j = 0; j < vertices; j++) {
 g->adj[i][j] = 0;
 }
 }
}

void addEdge(struct Graph *g, int v1, int v2) {
 // O(1)
 g->adj[v1][v2] = 1;
 g->adj[v2][v1] = 1; // Undirected graph
}

void displayGraph(struct Graph *g) {
 // O(V^2)
 int i, j;
 printf("Adjacency Matrix:\n");
 for (i = 0; i < g->vertices; i++) {
 for (j = 0; j < g->vertices; j++) {
 printf("%d ", g->adj[i][j]);
 }
 printf("\n");
 }
}

void demonstrateGraph() {
 printf("\n=== GRAPH ===\n");
 struct Graph g;
 initGraph(&g, 4);

 /*
 * Graph: 0 --- 1
 * | \ |
 * 2 --- 3
 */
 addEdge(&g, 0, 1);
 addEdge(&g, 0, 2);
 addEdge(&g, 0, 3);
 addEdge(&g, 1, 3);
 addEdge(&g, 2, 3);

 displayGraph(&g);
}


/* ================== MAIN FUNCTION ================== */
int main() {
 printf("===========================================\n");
 printf("Data Structures: Primitive vs Non-Primitive\n");
 printf("===========================================\n");

 // Primitive Data Types
 demonstratePrimitives();

 // Non-Primitive: Arrays
 demonstrateArray();

 // Non-Primitive: Linked List
 printf("\n=== LINKED LIST ===\n");
 struct LinkedList ll;
 initLinkedList(&ll);
 appendNode(&ll, 10);
 appendNode(&ll, 20);
 appendNode(&ll, 30);
 displayLinkedList(&ll);
 prependNode(&ll, 5);
 displayLinkedList(&ll);
 freeLinkedList(&ll);

 // Non-Primitive: Stack
 demonstrateStack();

 // Non-Primitive: Queue
 demonstrateQueue();

 // Non-Primitive: Binary Tree
 demonstrateBinaryTree();

 // Non-Primitive: Graph
 demonstrateGraph();

 printf("\n===========================================\n");
 printf("Program completed successfully!\n");
 printf("===========================================\n");

 return 0;
}
